import{_ as t,o as e,c as s,a2 as i}from"./chunks/framework.DdLJaIXX.js";const u=JSON.parse('{"title":"빠른 시작","description":"","frontmatter":{},"headers":[],"relativePath":"ko/guide/quickstart.md","filePath":"ko/guide/quickstart.md"}'),d={name:"ko/guide/quickstart.md"};function l(o,a,h,r,n,p){return e(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="빠른-시작" tabindex="-1">빠른 시작 <a class="header-anchor" href="#빠른-시작" aria-label="Permalink to &quot;빠른 시작&quot;">​</a></h1><p>설치부터 첫 GPU 연결 결과까지 2분.</p><h2 id="_1-설치" tabindex="-1">1. 설치 <a class="header-anchor" href="#_1-설치" aria-label="Permalink to &quot;1. 설치&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/PlayIdea-Lab/cq/main/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><h2 id="_2-실행" tabindex="-1">2. 실행 <a class="header-anchor" href="#_2-실행" aria-label="Permalink to &quot;2. 실행&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span></span></code></pre></div><p>CQ가 AI 도구 (Claude Code, Cursor, Codex, Gemini)를 자동 감지하고 연결합니다.</p><h2 id="_3-말하기" tabindex="-1">3. 말하기 <a class="header-anchor" href="#_3-말하기" aria-label="Permalink to &quot;3. 말하기&quot;">​</a></h2><p>그냥 말하세요. CQ가 크기에 맞게 자동 라우팅합니다:</p><h3 id="small-—-직접-수정-30초" tabindex="-1">Small — 직접 수정 (30초) <a class="header-anchor" href="#small-—-직접-수정-30초" aria-label="Permalink to &quot;Small — 직접 수정 (30초)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;auth/handler.go 42번 줄 타이포 고쳐줘&quot;</span></span></code></pre></div><p>CQ가 직접 처리. 계획 없음, Worker 없음. 바로 수정.</p><h3 id="medium-—-퀵-태스크-2분" tabindex="-1">Medium — 퀵 태스크 (2분) <a class="header-anchor" href="#medium-—-퀵-태스크-2분" aria-label="Permalink to &quot;Medium — 퀵 태스크 (2분)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/quick &quot;API에 health check 엔드포인트 추가&quot;</span></span></code></pre></div><p>CQ가 태스크 생성 (DoD 포함) → Worker 스폰 → 결과 제출. 한 커맨드.</p><h3 id="large-—-전체-파이프라인-5분" tabindex="-1">Large — 전체 파이프라인 (5분+) <a class="header-anchor" href="#large-—-전체-파이프라인-5분" aria-label="Permalink to &quot;Large — 전체 파이프라인 (5분+)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/pi &quot;리트라이 로직이 있는 웹훅 전송 시스템 만들기&quot;</span></span></code></pre></div><p>CQ가 브레인스토밍 → 계획 → 병렬 Worker → 다듬기 → 커밋. 커피 한 잔.</p><hr><h2 id="끝" tabindex="-1">끝 <a class="header-anchor" href="#끝" aria-label="Permalink to &quot;끝&quot;">​</a></h2><p>4단계는 없습니다. CQ가 각 요청에 맞는 워크플로우를 알아서 선택합니다.</p><p><strong>뒤에서 일어나는 일:</strong></p><ul><li>매 세션, CQ가 결정과 실험 결과를 캡처</li><li>5번째 세션부터 말하지 않아도 당신의 방식대로</li><li>지식은 AI 도구를 넘어 흐름 — ChatGPT에서 배운 것이 Claude에서도</li></ul><hr><h2 id="다음은" tabindex="-1">다음은? <a class="header-anchor" href="#다음은" aria-label="Permalink to &quot;다음은?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>하고 싶은 것</th><th>이동</th></tr></thead><tbody><tr><td>GPU 서버 연결하기</td><td><a href="/ko/guide/worker-setup.html">Worker 설정</a></td></tr><tr><td>Free/Pro/Team 티어 이해</td><td><a href="/ko/guide/tiers.html">티어</a></td></tr><tr><td>실제 버그 수정 과정 보기</td><td><a href="/ko/examples/bug-fix.html">버그 수정 예제</a></td></tr><tr><td>큰 기능 계획하고 만들기</td><td><a href="/ko/examples/feature-planning.html">기능 계획</a></td></tr><tr><td>ChatGPT를 CQ 워크스페이스에 연결</td><td><a href="/ko/examples/remote-mcp.html">Remote MCP</a></td></tr><tr><td>GPU 실험 자동 반복</td><td><a href="/ko/examples/research-loop.html">Research Loop</a></td></tr></tbody></table><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 뭐가 잘못됐는지 확인</span></span></code></pre></div><table tabindex="0"><thead><tr><th>증상</th><th>해결</th></tr></thead><tbody><tr><td>&quot;MCP server not found&quot;</td><td><code>.mcp.json</code> 바이너리 경로 확인; <code>cq doctor</code> 실행</td></tr><tr><td>macOS 코드 서명 에러</td><td><code>go build -o</code> 직접 사용, <code>cp</code> 금지</td></tr><tr><td>Python sidecar 에러</td><td><code>uv sync</code> 실행; Python 3.11+ 확인</td></tr></tbody></table>',29)])])}const k=t(d,[["render",l]]);export{u as __pageData,k as default};
